function getAvatarRingStyle(profile, tier) {
  const frame = AVATAR_FRAMES.find((f) => f.id === profile.equippedFrame);
  const colors = frame ? frame.colors : tier && tier.color ? [tier.color] : null;
  if (!colors) return null;
  return {
    background: colors.length > 1 ? `conic-gradient(${colors.join(", ")})` : colors[0],
    boxShadow: frame && frame.glow ? `0 0 10px ${colors[0]}` : void 0
  };
}
