  restart_tour_hint: { ru: "\u041A\u043E\u0440\u043E\u0442\u043A\u0430\u044F \u043F\u0440\u043E\u0433\u0443\u043B\u043A\u0430 \u043F\u043E \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u043C \u0440\u0430\u0437\u0434\u0435\u043B\u0430\u043C \u2014 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0443\u0434\u0430\u043B\u0438\u0442 \u0438 \u043D\u0435 \u0438\u0437\u043C\u0435\u043D\u0438\u0442.", en: "A quick walk through the main sections \u2014 won't delete or change anything.", zh: "\u7B80\u77ED\u6D4F\u89C8\u4E3B\u8981\u529F\u80FD\u533A\u2014\u2014\u4E0D\u4F1A\u5220\u9664\u6216\u66F4\u6539\u4EFB\u4F55\u5185\u5BB9\u3002" },
  whats_new_show_feature: { ru: "\u041F\u043E\u043A\u0430\u0437\u0430\u0442\u044C, \u043A\u0430\u043A \u044D\u0442\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442", en: "Show me how it works", zh: "\u5C55\u793A\u4F7F\u7528\u65B9\u6CD5" },
