  onboarding_at_open_desc: { ru: "\u041D\u0430\u0436\u043C\u0438\u0442\u0435 \u0441\u044E\u0434\u0430 \u2014 \u0442\u0430\u043C \u043F\u0440\u043E\u0433\u043D\u043E\u0437, \u0440\u0438\u0441\u043A\u0438 \u043F\u043E \u0431\u044E\u0434\u0436\u0435\u0442\u0430\u043C \u0438 \u043E\u0442\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044F \u043E\u0442 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0442\u0440\u0430\u0442.", en: "Click here \u2014 you'll find your forecast, budget risks, and deviations from your usual spending.", zh: "\u70B9\u51FB\u8FD9\u91CC\u2014\u2014\u53EF\u67E5\u770B\u9884\u6D4B\u3001\u9884\u7B97\u98CE\u9669\u4EE5\u53CA\u4E0E\u65E5\u5E38\u652F\u51FA\u7684\u504F\u5DEE\u3002" },
