  streak_none: { ru: "\u041D\u0430\u0447\u043D\u0438\u0442\u0435 \u0441\u0435\u0433\u043E\u0434\u043D\u044F, \u0447\u0442\u043E\u0431\u044B \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0441\u0435\u0440\u0438\u044E!", en: "Start today to begin your streak!", zh: "\u4ECA\u5929\u5F00\u59CB\u8BB0\u8D26,\u542F\u52A8\u8FDE\u7EED\u8BB0\u5F55!" },
