  month_summary_top_category: { ru: "\u0411\u043E\u043B\u044C\u0448\u0435 \u0432\u0441\u0435\u0433\u043E \u043F\u043E\u0442\u0440\u0430\u0447\u0435\u043D\u043E \u043D\u0430", en: "Biggest spend was on", zh: "\u6700\u5927\u652F\u51FA\u7C7B\u522B\u662F" },
  month_summary_budgets_ok: { ru: "\u043B\u0438\u043C\u0438\u0442\u044B \u043D\u0435 \u043F\u0440\u0435\u0432\u044B\u0448\u0435\u043D\u044B", en: "budgets were on track", zh: "\u9884\u7B97\u5747\u672A\u8D85\u652F" },
  month_summary_budgets_over: { ru: "\u043B\u0438\u043C\u0438\u0442(\u043E\u0432) \u043F\u0440\u0435\u0432\u044B\u0448\u0435\u043D\u043E", en: "budget(s) exceeded", zh: "\u4E2A\u9884\u7B97\u8D85\u652F" },
  month_summary_no_data: { ru: "\u0412 \u043F\u0440\u043E\u0448\u043B\u043E\u043C \u043C\u0435\u0441\u044F\u0446\u0435 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 \u043D\u0435 \u0431\u044B\u043B\u043E.", en: "No transactions last month.", zh: "\u4E0A\u6708\u6CA1\u6709\u4EA4\u6613\u8BB0\u5F55\u3002" },
